     5→//! VVC Probe - Claude Code environment probe
     6→//!
     7→//! Discovers model IDs and platform information by spawning minimal claude invocations.
     8→//! See Tools/vok/vov_veiled/VOSRP-probe.adoc for specification.
     9→
    10→use chrono::{DateTime, Local, Utc};
    11→use tokio::process::Command;
    12→
    13→/// Brand prefix for VVC commits
    14→pub const VVCC_BRAND_PREFIX: &str = "vvb";
    15→
    16→/// Action code for invitatory commits
    17→pub const VVCP_ACTION_INVITATORY: &str = "i";
    18→
    19→/// Officium token for invitatory commit subjects
    20→pub const VVCP_OFFICIUM_TOKEN: &str = "OFFICIUM";
    21→
    22→/// Gap threshold in seconds for officium detection (1 hour)
    23→pub const VVCP_OFFICIUM_GAP_SECS: u64 = 3;
    24→
    25→/// Probe Claude Code environment for model IDs and platform information.
    26→///
    27→/// Spawns three parallel claude invocations to discover actual model versions.
    28→/// Returns a 5-line string in "key: value" format.
    29→///
    30→/// # Returns
    31→///
    32→/// Five-line string:
    33→/// ```text
    34→/// haiku: claude-3-5-haiku-20241022
    35→/// sonnet: claude-sonnet-4-20250514
    36→/// opus: claude-opus-4-5-20251101
    37→/// host: macbook-pro.local
    38→/// platform: darwin-arm64
    39→/// ```
    40→///
    41→/// On probe failure for a tier, returns "unavailable" for that tier.
    42→pub async fn vvcp_probe() -> Result<String, String> {
    43→    // Spawn three parallel claude invocations to probe model IDs
    44→    let haiku_future = probe_model_tier("haiku");
    45→    let sonnet_future = probe_model_tier("sonnet");
    46→    let opus_future = probe_model_tier("opus");
    47→
    48→    // Wait for all three probes in parallel
    49→    let (haiku_id, sonnet_id, opus_id) = tokio::join!(haiku_future, sonnet_future, opus_future);
    50→
    51→    // Collect hostname
    52→    let hostname = get_hostname().await;
    53→
    54→    // Collect platform (OS and architecture)
    55→    let platform = get_platform().await;
    56→
    57→    // Format as 5-line string
    58→    let result = format!(
    59→        "haiku: {}\nsonnet: {}\nopus: {}\nhost: {}\nplatform: {}",
    60→        haiku_id, sonnet_id, opus_id, hostname, platform
    61→    );
    62→
    63→    Ok(result)
    64→}
