    66→/// Probe a single model tier by invoking claude with minimal prompt
    67→async fn probe_model_tier(tier: &str) -> String {
    68→    let output = Command::new("claude")
    69→        .args([
    70→            "-p",
    71→            "--model",
    72→            tier,
    73→            "--no-session-persistence",
    74→            "--",
    75→            "Report your exact model ID string only",
    76→        ])
    77→        .output()
    78→        .await;
    79→
    80→    match output {
    81→        Ok(output) if output.status.success() => {
    82→            String::from_utf8_lossy(&output.stdout).trim().to_string()
    83→        }
    84→        _ => "unavailable".to_string(),
    85→    }
    86→}
    87→
    88→/// Get hostname via std::env or hostname command
    89→async fn get_hostname() -> String {
    90→    // Try environment variable first
    91→    if let Ok(hostname) = std::env::var("HOSTNAME") {
    92→        return hostname;
    93→    }
    94→
    95→    // Fall back to hostname command
    96→    let output = Command::new("hostname").output().await;
    97→
    98→    match output {
    99→        Ok(output) if output.status.success() => {
   100→            String::from_utf8_lossy(&output.stdout).trim().to_string()
   101→        }
   102→        _ => "unknown".to_string(),
   103→    }
   104→}
   105→
   106→/// Get platform information (OS and architecture)
   107→async fn get_platform() -> String {
   108→    // Spawn uname -s and uname -m in parallel
   109→    let os_future = Command::new("uname").arg("-s").output();
   110→    let arch_future = Command::new("uname").arg("-m").output();
   111→
   112→    let (os_result, arch_result) = tokio::join!(os_future, arch_future);
   113→
   114→    let os = match os_result {
   115→        Ok(output) if output.status.success() => {
   116→            String::from_utf8_lossy(&output.stdout).trim().to_lowercase()
   117→        }
   118→        _ => "unknown".into(),
   119→    };
   120→
   121→    let arch = match arch_result {
   122→        Ok(output) if output.status.success() => {
   123→            String::from_utf8_lossy(&output.stdout).trim().to_string()
   124→        }
   125→        _ => "unknown".to_string(),
   126→    };
   127→
   128→    format!("{}-{}", os, arch)
   129→}
   130→
   131→/// Check if an officium invitatory is needed
   132→///
   133→/// Searches git log for most recent invitatory commit (vvb:...:i:) and checks
   134→/// if the time gap exceeds VVCP_OFFICIUM_GAP_SECS (1 hour).
   135→///
   136→/// Returns true if no invitatory found OR gap exceeds threshold.
   137→pub(crate) async fn zvvcp_needs_officium() -> bool {
   138→    // Build grep pattern from constants
   139→    let pattern = format!("^{}:.*:{}:", VVCC_BRAND_PREFIX, VVCP_ACTION_INVITATORY);
   140→
   141→    // Search git log for most recent invitatory commit
   142→    let output = Command::new("git")
   143→        .args([
   144→            "log",
   145→            "--all",
   146→            &format!("--grep={}", pattern),
   147→            "--format=%ai",
   148→            "-1",
   149→        ])
   150→        .output()
   151→        .await;
   152→
   153→    let timestamp_str = match output {
   154→        Ok(output) if output.status.success() => {
   155→            let output_str = String::from_utf8_lossy(&output.stdout);
   156→            let trimmed = output_str.trim();
   157→            if trimmed.is_empty() {
   158→                // No invitatory commit found
   159→                return true;
   160→            }
   161→            trimmed.to_string()
   162→        }
   163→        _ => {
   164→            // Git command failed or no commits found
   165→            return true;
   166→        }
   167→    };
   168→
   169→    // Parse timestamp (format: "2026-02-07 14:30:00 -0800")
   170→    let parsed_time = match DateTime::parse_from_str(&timestamp_str, "%Y-%m-%d %H:%M:%S %z") {
   171→        Ok(dt) => dt.with_timezone(&Utc),
   172→        Err(_) => {
   173→            // Parse error - assume gap needed
   174→            return true;
   175→        }
   176→    };
   177→
   178→    let now = Utc::now();
   179→    let gap_secs = (now - parsed_time).num_seconds();
   180→
   181→    gap_secs.abs() as u64 > VVCP_OFFICIUM_GAP_SECS
   182→}
   183→
   184→/// Create an invitatory commit to open a new officium
   185→///
   186→/// Checks if invitatory is needed via zvvcp_needs_officium().
   187→/// If not needed, prints "Officium current" and returns Ok.
   188→/// Otherwise, probes for model IDs, gets hallmark, and creates
   189→/// an empty branded commit with OFFICIUM timestamp.
   190→pub async fn vvcp_invitatory() -> Result<(), String> {
   191→    // Check if invitatory is needed
   192→    if !zvvcp_needs_officium().await {
   193→        println!("Officium current");
   194→        return Ok(());
   195→    }
   196→
   197→    // Probe for model IDs
   198→    let probe_data = vvcp_probe().await?;
   199→
   200→    // Get hallmark
   201→    let hallmark = crate::vvcc_get_hallmark();
   202→
   203→    // Generate timestamp in YYMMDD-HHMM format
   204→    let now = Local::now();
   205→    let timestamp = now.format("%y%m%d-%H%M").to_string();
   206→
   207→    // Format subject
   208→    let subject = format!("{} {}", VVCP_OFFICIUM_TOKEN, timestamp);
   209→
   210→    // Format commit message
   211→    let message = crate::vvcc_format_branded(
   212→        VVCC_BRAND_PREFIX,
   213→        &hallmark,
   214→        "",
   215→        VVCP_ACTION_INVITATORY,
   216→        &subject,
   217→        Some(&probe_data),
   218→    );
   219→
   220→    // Create commit arguments
   221→    let commit_args = crate::vvcc_CommitArgs {
   222→        prefix: None,
   223→        message: Some(message),
   224→        allow_empty: true,
   225→        no_stage: true,
   226→        size_limit: crate::VVCG_SIZE_LIMIT,
   227→        warn_limit: crate::VVCG_WARN_LIMIT,
   228→    };
   229→
   230→    // Create empty commit
   231→    let hash = match crate::vvcc_CommitLock::vvcc_acquire() {
   232→        Ok(lock) => lock.vvcc_commit(&commit_args)?,
   233→        Err(e) => return Err(format!("Failed to acquire lock: {}", e)),
   234→    };
   235→
   236→    println!("Officium: {} ({})", hash, timestamp);
   237→
   238→    Ok(())
   239→}
   240→
   241→#[cfg(test)]
   242→mod tests {
   243→    use super::*;
   244→
   245→    #[tokio::test]
   246→    async fn test_probe_output_format() {
   247→        // This test verifies the output format structure
   248→        // Actual model IDs may be "unavailable" in test environments
   249→        let result = vvcp_probe().await;
   250→
   251→        assert!(result.is_ok());
   252→        let output = result.unwrap();
   253→
   254→        // Should have exactly 5 lines
   255→        let lines: Vec<&str> = output.lines().collect();
   256→        assert_eq!(lines.len(), 5, "Expected 5 lines, got: {}", output);
   257→
   258→        // Verify line format (key: value)
   259→        assert!(lines[0].starts_with("haiku: "), "Line 0: {}", lines[0]);
   260→        assert!(lines[1].starts_with("sonnet: "), "Line 1: {}", lines[1]);
   261→        assert!(lines[2].starts_with("opus: "), "Line 2: {}", lines[2]);
   262→        assert!(lines[3].starts_with("host: "), "Line 3: {}", lines[3]);
   263→        assert!(lines[4].starts_with("platform: "), "Line 4: {}", lines[4]);
   264→
   265→        // Verify each line has content after the colon
   266→        for (i, line) in lines.iter().enumerate() {
   267→            let parts: Vec<&str> = line.splitn(2, ": ").collect();
   268→            assert_eq!(parts.len(), 2, "Line {} missing colon separator: {}", i, line);
   269→            assert!(!parts[1].is_empty(), "Line {} has empty value: {}", i, line);
   270→        }
   271→    }
   272→
   273→    #[tokio::test]
   274→    async fn test_get_hostname() {
   275→        let hostname = get_hostname().await;
   276→        assert!(!hostname.is_empty());
   277→        assert_ne!(hostname, "unknown");
   278→    }
   279→
   280→    #[tokio::test]
   281→    async fn test_get_platform() {
   282→        let platform = get_platform().await;
   283→        assert!(platform.contains('-'), "Platform should be OS-ARCH format");
   284→        assert!(!platform.starts_with("unknown-"), "OS should be detected");
   285→    }
   286→}
